            }
        } catch (NumberFormatException nfe) {
            return 0;
        }

        if (entityValue < 0 || entityValue > Character.MAX_CODE_POINT) {
            return 0;
        }

        if (entityValue > Character.MAX_VALUE) {
            char[] chars = Character.toChars(entityValue);
            out.write(chars);
